async function initTrafficCounter(){const counterElement=document.getElementById("pageViews");if(!counterElement)return;const namespace="snixrs-portfolio";const path=window.location.pathname.replace(/\//g,"_").replace(".html","")||"home";const key=`page_${path}`;try{const response=await fetch(`https://api.counterapi.dev/v1/${namespace}/${key}/up`);if(response.ok){const data=await response.json();const count=data.count;console.log(`Traffic: ${count}`);const formattedCount=(new Intl.NumberFormat).format(count);counterElement.innerHTML=`\n                <span class="view-counter-badge">\n                    <i class="fas fa-eye"></i>\n                    <span class="view-count-number">${formattedCount}</span>\n                </span>\n            `;counterElement.classList.add("visible")}else{console.warn("Traffic counter API returned an error.");counterElement.style.display="none"}}catch(error){console.error("Error fetching traffic data:",error);counterElement.style.display="none"}}document.addEventListener("DOMContentLoaded",initTrafficCounter);